import{_ as e,o as r,c as d,a2 as o}from"./chunks/framework.N6Nd-M9-.js";const b=JSON.parse('{"title":"公司需要什么样的人——新人篇","description":"","frontmatter":{},"headers":[],"relativePath":"notes/培训/六大会议/06—公司需要什么样的人——新人篇.md","filePath":"notes/培训/六大会议/06—公司需要什么样的人——新人篇.md"}'),p={name:"notes/培训/六大会议/06—公司需要什么样的人——新人篇.md"};function a(t,i,l,n,s,g){return r(),d("div",null,[...i[0]||(i[0]=[o('<h1 id="公司需要什么样的人——新人篇" tabindex="-1">公司需要什么样的人——新人篇 <a class="header-anchor" href="#公司需要什么样的人——新人篇" aria-label="Permalink to &quot;公司需要什么样的人——新人篇&quot;">​</a></h1><h2 id="一、核心答案-态度-能力-🎯" tabindex="-1">一、核心答案：态度 &gt; 能力 🎯 <a class="header-anchor" href="#一、核心答案-态度-能力-🎯" aria-label="Permalink to &quot;一、核心答案：态度 &gt; 能力 🎯&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;margin:20px 0;"><div style="background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;border-left:4px solid #667eea;"><p style="color:#333;font-size:15px;margin:0;line-height:1.7;">💡 对于新人，公司最看重的<strong style="color:#667eea;">不是能力</strong>（能力可以培养），而是<strong style="color:#667eea;">态度</strong>（态度决定一切）。</p></div></div><h2 id="二、公司需要的新人特质-🌟" tabindex="-1">二、公司需要的新人特质 🌟 <a class="header-anchor" href="#二、公司需要的新人特质-🌟" aria-label="Permalink to &quot;二、公司需要的新人特质 🌟&quot;">​</a></h2><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:15px;margin:20px 0;"><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);color:#333;padding:20px;border-radius:12px;"><p style="font-size:24px;font-weight:bold;margin:0 0 12px 0;color:#667eea;">1️⃣ 主动学习</p><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><p style="font-size:14px;margin:0 0 8px 0;line-height:1.6;"><strong>表现</strong>：</p><ul style="margin:0;padding-left:18px;font-size:14px;line-height:1.6;"><li>主动请教，不等不靠</li><li>认真记录，反复练习</li><li>不懂就问，不装懂</li></ul><p style="font-size:14px;margin:8px 0 0 0;line-height:1.6;"><strong>反例</strong>：被动等待安排，教一遍就觉得自己会了。</p></div></div><div style="background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);color:#333;padding:20px;border-radius:12px;"><p style="font-size:24px;font-weight:bold;margin:0 0 12px 0;color:#22c55e;">2️⃣ 踏实肯干</p><div style="background:rgba(34,197,94,0.08);padding:12px;border-radius:8px;border-left:4px solid #22c55e;"><p style="font-size:14px;margin:0 0 8px 0;line-height:1.6;"><strong>表现</strong>：</p><ul style="margin:0;padding-left:18px;font-size:14px;line-height:1.6;"><li>接受外勤安排，不挑三拣四</li><li>认真对待每一个客户</li><li>不抱怨，不推诿</li></ul><p style="font-size:14px;margin:8px 0 0 0;line-height:1.6;"><strong>反例</strong>：嫌累嫌苦，总想找捷径。</p></div></div><div style="background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);color:#333;padding:20px;border-radius:12px;"><p style="font-size:24px;font-weight:bold;margin:0 0 12px 0;color:#f59e0b;">3️⃣ 积极乐观</p><div style="background:rgba(245,158,11,0.08);padding:12px;border-radius:8px;border-left:4px solid #f59e0b;"><p style="font-size:14px;margin:0 0 8px 0;line-height:1.6;"><strong>表现</strong>：</p><ul style="margin:0;padding-left:18px;font-size:14px;line-height:1.6;"><li>面对拒绝不气馁</li><li>遇到困难想办法</li><li>传递正能量，不传播负面</li></ul><p style="font-size:14px;margin:8px 0 0 0;line-height:1.6;"><strong>反例</strong>：遇到挫折就抱怨，传播负能量。</p></div></div><div style="background:rgba(59,130,246,0.06);border:1px solid rgba(59,130,246,0.15);color:#333;padding:20px;border-radius:12px;"><p style="font-size:24px;font-weight:bold;margin:0 0 12px 0;color:#3b82f6;">4️⃣ 团队意识</p><div style="background:rgba(59,130,246,0.08);padding:12px;border-radius:8px;border-left:4px solid #3b82f6;"><p style="font-size:14px;margin:0 0 8px 0;line-height:1.6;"><strong>表现</strong>：</p><ul style="margin:0;padding-left:18px;font-size:14px;line-height:1.6;"><li>服从团队安排</li><li>乐于帮助队友</li><li>维护团队利益</li></ul><p style="font-size:14px;margin:8px 0 0 0;line-height:1.6;"><strong>反例</strong>：只顾自己，我行我素。</p></div></div><div style="background:rgba(236,72,153,0.06);border:1px solid rgba(236,72,153,0.15);color:#333;padding:20px;border-radius:12px;"><p style="font-size:24px;font-weight:bold;margin:0 0 12px 0;color:#ec4899;">5️⃣ 有目标感</p><div style="background:rgba(236,72,153,0.08);padding:12px;border-radius:8px;border-left:4px solid #ec4899;"><p style="font-size:14px;margin:0 0 8px 0;line-height:1.6;"><strong>表现</strong>：</p><ul style="margin:0;padding-left:18px;font-size:14px;line-height:1.6;"><li>知道自己要什么</li><li>有明确的阶段性目标</li><li>为目标持续努力</li></ul><p style="font-size:14px;margin:8px 0 0 0;line-height:1.6;"><strong>反例</strong>：得过且过，混日子。</p></div></div></div><h2 id="三、新人常见的误区-⚠️" tabindex="-1">三、新人常见的误区 ⚠️ <a class="header-anchor" href="#三、新人常见的误区-⚠️" aria-label="Permalink to &quot;三、新人常见的误区 ⚠️&quot;">​</a></h2><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);padding:20px;border-radius:12px;margin:20px 0;"><p style="color:#ef4444;font-weight:bold;font-size:18px;margin:0 0 15px 0;">🚫 新人常见的五大误区</p><div style="display:flex;flex-wrap:wrap;gap:12px;"><div style="background:rgba(239,68,68,0.08);padding:12px;border-radius:8px;flex:1;min-width:200px;border-left:4px solid #ef4444;"><p style="color:#333;font-size:14px;margin:0;line-height:1.6;"><strong>误区一</strong>：觉得工作简单，不用心学</p></div><div style="background:rgba(239,68,68,0.08);padding:12px;border-radius:8px;flex:1;min-width:200px;border-left:4px solid #ef4444;"><p style="color:#333;font-size:14px;margin:0;line-height:1.6;"><strong>误区二</strong>：急于求成，想快速赚钱</p></div><div style="background:rgba(239,68,68,0.08);padding:12px;border-radius:8px;flex:1;min-width:200px;border-left:4px solid #ef4444;"><p style="color:#333;font-size:14px;margin:0;line-height:1.6;"><strong>误区三</strong>：玻璃心，受不了批评</p></div><div style="background:rgba(239,68,68,0.08);padding:12px;border-radius:8px;flex:1;min-width:200px;border-left:4px solid #ef4444;"><p style="color:#333;font-size:14px;margin:0;line-height:1.6;"><strong>误区四</strong>：眼高手低，挑肥拣瘦</p></div><div style="background:rgba(239,68,68,0.08);padding:12px;border-radius:8px;flex:1;min-width:200px;border-left:4px solid #ef4444;"><p style="color:#333;font-size:14px;margin:0;line-height:1.6;"><strong>误区五</strong>：频繁换工作，没有定性</p></div></div></div><h2 id="四、新人成长的关键阶段-📈" tabindex="-1">四、新人成长的关键阶段 📈 <a class="header-anchor" href="#四、新人成长的关键阶段-📈" aria-label="Permalink to &quot;四、新人成长的关键阶段 📈&quot;">​</a></h2><div style="display:flex;flex-direction:column;gap:12px;margin:20px 0;"><div style="display:flex;align-items:center;gap:15px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);color:#333;padding:18px 20px;border-radius:12px;"><div style="background:rgba(102,126,234,0.15);padding:10px 18px;border-radius:10px;font-weight:bold;font-size:16px;white-space:nowrap;color:#667eea;">第1周</div><div style="flex:1;"><p style="margin:0;font-weight:bold;font-size:18px;">👀 观察期</p><p style="margin:5px 0 0 0;font-size:14px;">了解公司、熟悉流程、认识同事</p></div></div><div style="display:flex;align-items:center;gap:15px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);color:#333;padding:18px 20px;border-radius:12px;"><div style="background:rgba(34,197,94,0.15);padding:10px 18px;border-radius:10px;font-weight:bold;font-size:16px;white-space:nowrap;color:#22c55e;">第2-4周</div><div style="flex:1;"><p style="margin:0;font-weight:bold;font-size:18px;">📚 学习期</p><p style="margin:5px 0 0 0;font-size:14px;">学习话术、跟随实践、掌握基础技能</p></div></div><div style="display:flex;align-items:center;gap:15px;background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);color:#333;padding:18px 20px;border-radius:12px;"><div style="background:rgba(245,158,11,0.15);padding:10px 18px;border-radius:10px;font-weight:bold;font-size:16px;white-space:nowrap;color:#f59e0b;">第2-3月</div><div style="flex:1;"><p style="margin:0;font-weight:bold;font-size:18px;">💪 实践期</p><p style="margin:5px 0 0 0;font-size:14px;">独立作业、积累经验、形成自己的方法</p></div></div><div style="display:flex;align-items:center;gap:15px;background:rgba(236,72,153,0.06);border:1px solid rgba(236,72,153,0.15);color:#333;padding:18px 20px;border-radius:12px;"><div style="background:rgba(236,72,153,0.15);padding:10px 18px;border-radius:10px;font-weight:bold;font-size:16px;white-space:nowrap;color:#ec4899;">第3月+</div><div style="flex:1;"><p style="margin:0;font-weight:bold;font-size:18px;">🚀 突破期</p><p style="margin:5px 0 0 0;font-size:14px;">业绩稳定、开始带新人、向组长发展</p></div></div></div><h2 id="五、给新人的建议-💡" tabindex="-1">五、给新人的建议 💡 <a class="header-anchor" href="#五、给新人的建议-💡" aria-label="Permalink to &quot;五、给新人的建议 💡&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:12px;margin:20px 0;"><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;flex:1;min-width:280px;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><p style="color:#667eea;font-weight:bold;font-size:16px;margin:0 0 10px 0;">🎯 关于心态</p><p style="color:#333;font-size:14px;margin:0;line-height:1.6;">空杯心态，从零开始。不要带着过去的&quot;经验&quot;来评判现在的工作。</p></div></div><div style="background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:20px;border-radius:12px;flex:1;min-width:280px;"><div style="background:rgba(34,197,94,0.08);padding:12px;border-radius:8px;border-left:4px solid #22c55e;"><p style="color:#22c55e;font-weight:bold;font-size:16px;margin:0 0 10px 0;">📚 关于学习</p><p style="color:#333;font-size:14px;margin:0;line-height:1.6;">多看、多听、多问、多练。前三个月是学习黄金期，错过就很难补。</p></div></div><div style="background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);padding:20px;border-radius:12px;flex:1;min-width:280px;"><div style="background:rgba(245,158,11,0.08);padding:12px;border-radius:8px;border-left:4px solid #f59e0b;"><p style="color:#f59e0b;font-weight:bold;font-size:16px;margin:0 0 10px 0;">⏰ 关于时间</p><p style="color:#333;font-size:14px;margin:0;line-height:1.6;">给自己至少3-6个月的时间。任何工作都需要时间适应和成长。</p></div></div><div style="background:rgba(59,130,246,0.06);border:1px solid rgba(59,130,246,0.15);padding:20px;border-radius:12px;flex:1;min-width:280px;"><div style="background:rgba(59,130,246,0.08);padding:12px;border-radius:8px;border-left:4px solid #3b82f6;"><p style="color:#3b82f6;font-weight:bold;font-size:16px;margin:0 0 10px 0;">🤝 关于关系</p><p style="color:#333;font-size:14px;margin:0;line-height:1.6;">与领队、组长保持良好沟通。他们是你成长的引路人。</p></div></div></div><h2 id="六、总结-📝" tabindex="-1">六、总结 📝 <a class="header-anchor" href="#六、总结-📝" aria-label="Permalink to &quot;六、总结 📝&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;margin:20px 0;"><div style="background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;border-left:4px solid #667eea;"><p style="color:#333;font-size:15px;margin:0;line-height:1.7;">📌 公司需要的新人，<strong style="color:#667eea;">不是最聪明的，而是最靠谱的</strong>。态度端正、踏实肯干、积极学习、有团队意识、有目标感——这些特质比能力更重要，因为能力可以培养，而态度决定了一切。</p></div></div>',13)])])}const f=e(p,[["render",a]]);export{b as __pageData,f as default};
